const{execSync:execSync}=require("child_process"),fs=require("fs"),path=require("path");function runRustdocJson(o,e){try{execSync("cargo +nightly rustdoc --lib -- -Z unstable-options --output-format json",{cwd:o,stdio:"inherit"});const n=path.join(o,"target","doc"),t=fs.readdirSync(n).find(o=>o.endsWith(".json"));t&&(fs.copyFileSync(path.join(n,t),e),console.log(`API JSON written to ${e}`))}catch(n){console.error("Failed to generate rustdoc JSON:",n)}}function main(){runRustdocJson(path.resolve(__dirname,"../../crates/forge-cli"),path.resolve(__dirname,"../docs/api-forge-cli.json"))}main();